mapper.select:
SELECT a.appointment_id, a.appointment_no, a.patient_id, p.name AS patient_name, a.doctor_id, d.name AS doctor_name, d.title AS doctor_title, dept.name AS dept_name, DATE_FORMAT(a.appointment_date, '%Y-%m-%d') AS appointment_date, a.time_slot, a.queue_no, a.status, a.fee_amount, a.paid, a.created_time FROM appointment a LEFT JOIN patient p ON a.patient_id = p.patient_id LEFT JOIN doctor d ON a.doctor_id = d.doctor_id LEFT JOIN sys_dept dept ON d.dept_id = dept.dept_id WHERE a.patient_id = #{patientId}
AND a.status = #{status}
ORDER BY a.appointment_date DESC, a.created_time DESC
